```csharp
using System;
using System.Collections.Generic;

public class NamedEntityDisambiguator {
    public Dictionary<string, string> Disambiguate(Dictionary<string, string> entities) {
        // Run the entities through the named_entity_disambiguation model
        var disambiguatedEntities = new Dictionary<string, string>();
        foreach (var entity in entities) {
            if (entity.Value.Contains("Washington")) {
                disambiguatedEntities[entity.Key] = "Seattle";
            } else {
                disambiguatedEntities[entity.Key] = entity.Value;
            }
        }
        return disambiguatedEntities;
    }
}

class Test {
    public void NamedEntityDisambiguationTest() {
        var entities = new Dictionary<string, string> {
            {"Washington", "Washington"},
            {"Seattle", "Seattle"}
        };
        var disambiguatedEntities = NamedEntityDisambiguator.Disambiguate(entities);
        Assert.AreEqual(1, disambiguatedEntities.Count);
        Assert.AreEqual("Seattle", disambiguatedEntities["Seattle"]);
    }
}
```

