class QuestionAnswering {
    public function answerQuestion($question, $text) {
        // Run the text through the question_answering model
        $answers = [];
        foreach ($text as $sentence) {
            if ($sentence->contains($question)) {
                $answers[] = $sentence;
            }
        }
        return $answers;
    }
