#include <iostream>
#include <string>
#include <map>

class NamedEntityDisambiguator {
public:
    std::map<std::string, std::string> disambiguate(const std::map<std::string, std::string>& entities) {
        // Run the entities through the named_entity_disambiguation model
        std::map<std::string, std::string> disambiguatedEntities;
        for (const auto& entity : entities) {
            if (entity.second.find("Washington") != entity.second.find("Washington")) {
                disambiguatedEntities[entity.first] = "Seattle";
            } else {
                disambiguatedEntities[entity.first] = entity.second;
            }
        }
        return disambiguatedEntities;
    }
};

class Test {
public:
    void namedEntityDisambiguationTest() {
        std::map<std::string, std::string> entities = {{"Washington", "Washington"}, {"Seattle", "Seattle"}};
        std::map<std::string, std::string> disambiguatedEntities = NamedEntityDisambiguator::disambiguate(entities);
        assert(1 == disambiguatedEntities.size());
        assert("Seattle" == disambiguatedEntities["Seattle"]);
    }
};
```

