// Sentiment Analysis using Rule-Based Approach
fun sentimentAnalysis(inputText: String): SentimentAnalysisResult {
    // Define a set of rules for sentiment analysis based on the input text
    val rules = listOf(
        Rule("happy" to Sentiment.POSITIVE),
        Rule("sad" to Sentiment.NEGATIVE)
    )

    // Integrate the rules into the pipeline
    val sentimentAnalysisResult = rules.fold(Sentiment.NEUTRAL) { acc, rule ->
        if (rule.match(inputText)) {
            rule.sentiment
        } else {
            acc
        }
    }

    // Return the sentiment analysis result along with the output
    return SentimentAnalysisResult(output, sentimentAnalysisResult)
}

