// Spell Checking using a Dictionary-Based Approach
function spellCheck(inputText: string): string[] {
    // Create a dictionary of words and their corresponding spellings
    const dictionary = {
        "hello": ["hello", "hallo", "helllo"],
        "world": ["world", "worlld", "worlld"]
    };

    // Perform spell checking using the dictionary
    const corrections = Object.keys(dictionary).filter((word) => {
        return !inputText.includes(word);
    });

    // Return the list of suggested corrections along with the output
    return corrections;
}

