// Part-of-speech tagging using a rule-based approach
func partOfSpeechTagging(inputText: String) -> [String: String] {
    // Define a set of rules for part-of-speech tagging based on the input text
    let rules = [
        ("hello", "noun"),
        ("world", "noun"),
        ("is", "verb"),
        ("a", "article")
    ]

    // Integrate the rules into the pipeline
    let taggedPartsOfSpeech = rules.reduce(into: [:]) { $0[$1.key] = $1.value; return $0 }

